{
  "premium_report": {
    "report_title": "프리미엄 사주 리포트",
    "version": "1.0",
    "sections": [
      {
        "section_id": "overall_1",
        "category": "overall",
        "title": "프리미엄 사주 스토리",
        "headline": "현실적 판단으로 흐름을 다듬는 사람",
        "summary_lines": [
          "지금은 목표를 향한 흐름을 찾으며 일을 차근차근 완성하는 방향으로 기운이 모이고 있습니다.",
          "대화에서는 상대의 의도와 맥락을 먼저 파악하고 말의 흐름을 정리하는 습관이 나타납니다.",
          "초기에 세운 기준을 지나치게 흔들지 않는 편이라 상황이 바뀌어도 핵심 목표를 잃지 않는 편입니다."
        ],
        "core_insight": "당신은 현실적인 흐름을 먼저 읽고 여러 선택지가 있어도 시작점의 방향을 먼저 정하는 습관이 특징입니다. 상황이 바뀌어도 처음 세운 기준을 크게 흔들지 않으려는 마음가짐이 돋보이고, 상대의 말과 마음의 흐름을 차분히 정리해 전달하는 과정에서 신뢰를 쌓아 갑니다. 이러한 특징은 실제로 일을 이어가는 흐름을 매끄럽게 만들어 줍니다.",
        "strength": "상황의 흐름을 빨리 파악하고 말의 순서와 전달 방식을 가다듬는 능력이 있어, 관계를 원활하게 이끌어 가는 힘이 있습니다.",
        "risk": "변화가 크지 않은 상황에서도 새로운 아이디어나 방법을 도입하는 데 시간이 걸릴 수 있어, 충분한 검토와 소통으로 속도를 조금씩 높이는 노력이 필요합니다.",
        "action_points": [
          "주변 상황을 먼저 살핀 뒤 말의 흐름과 순서를 정리한 뒤 의사결정을 내리세요.",
          "작은 실제 행동부터 시작해 점진적으로 계획을 확장하는 습관을 들이세요.",
          "약속은 지키고 피드백을 자주 받아 관계의 흐름을 매끄럽게 만드세요."
        ],
        "action_note": "일상의 작은 루틴으로 바꿔 실천하시면 흐름이 안정적으로 자리잡을 것입니다."
      }
    ]
  }
}
